INSERT INTO `messages` (`id`, `sender_id`, `receiver_id`, `message`, `is_read`) VALUES  
(134, 42, 62, 'Bonsoir, c''est du cuir véritable ?', 1),
(135, 62, 42, 'Bonsoir, oui c''est du cuir de vachette 100% véritable.', 1),
(136, 42, 62, 'D''accord, et ça ne s''abîme pas avec l''eau ?', 1),
