INSERT INTO `messages` (`id`, `sender_id`, `receiver_id`, `message`, `is_read`) VALUES 
(68, 26, 62, 'Bonjour, est-ce que ce produit est sous garantie ?', 1),
(69, 62, 26, 'Bonjour ! Oui, il a une garantie constructeur de 12 mois.', 1),
(70, 26, 62, 'Parfait. Et si j''ai un problème, je vous le ramène ou je contacte le constructeur ?', 1),
(71, 62, 26, 'Vous passez par moi directement, je m''occupe du SAV.', 1),
(72, 26, 62, 'Excellent, je passe la commande de suite.', 1),
(73, 62, 26, 'Merci pour votre confiance !', 1);
INSERT INTO `messages` (`id`, `sender_id`, `receiver_id`, `message`, `is_read`) VALUES 
(74, 32, 67, 'Salut, je suis intéressé par plusieurs articles. Vous faites un prix de gros ?', 1),
(75, 67, 32, 'Bonjour. Oui, à partir de 5 articles je peux vous faire -15%.', 1),
(76, 32, 67, 'Je vais en prendre 6. Comment on fait pour le paiement avec la réduction ?', 1),
(77, 67, 32, 'Passez la commande, choisissez paiement à la livraison, et je déduirai la réduction sur la facture finale.', 1),
(78, 32, 67, 'C''est noté, commande passée.', 1),
(79, 67, 32, 'Bien reçu, je prépare le colis.', 0);
INSERT INTO `messages` (`id`, `sender_id`, `receiver_id`, `message`, `is_read`) VALUES 
(80, 22, 67, 'Bonjour, le produit est exactement comme sur la photo ?', 1),
(81, 67, 22, 'Bonjour, oui ce sont nos propres photos, le produit est 100% identique.', 1),
(82, 22, 67, 'D''accord, car j''ai eu de mauvaises surprises avec d''autres vendeurs.', 1),
(83, 67, 22, 'Ne vous inquiétez pas, vous pouvez vérifier le colis avant de payer le livreur.', 1),
(84, 22, 67, 'Super, ça me rassure. Merci.', 1),
(85, 67, 22, 'A votre service !', 0);
INSERT INTO `messages` (`id`, `sender_id`, `receiver_id`, `message`, `is_read`) VALUES 
(86, 39, 64, 'Bonsoir, l''article est neuf ou reconditionné ?', 1),
(87, 64, 39, 'Bonsoir, c''est un article 100% neuf, sous blister.', 1),
(88, 39, 64, 'D''accord, et vous livrez à Kairouan ?', 1),
(89, 64, 39, 'Oui, la livraison se fait partout en Tunisie en 24/48h.', 1),
(90, 39, 64, 'Parfait, je vais commander.', 1),
(91, 64, 39, 'Merci, bonne soirée.', 1);
INSERT INTO `messages` (`id`, `sender_id`, `receiver_id`, `message`, `is_read`) VALUES 
(92, 27, 63, 'Salut, est-ce qu''il y a d''autres couleurs disponibles ?', 1),
(93, 63, 27, 'Salut, oui nous avons noir, blanc, et bleu.', 1),
(94, 27, 63, 'Le bleu est foncé ou clair ?', 1),
(95, 63, 27, 'C''est un bleu nuit, assez foncé.', 1),
(96, 27, 63, 'Ok, mettez-moi un bleu s''il vous plaît.', 1),
(97, 63, 27, 'C''est noté dans votre dossier. Merci.', 0);
INSERT INTO `messages` (`id`, `sender_id`, `receiver_id`, `message`, `is_read`) VALUES 
(98, 35, 61, 'Bonjour, je n''arrive pas à utiliser le code promo.', 1),
(99, 61, 35, 'Bonjour, quel code essayez-vous d''utiliser ?', 1),
(100, 35, 61, 'Le code BIENVENUE10.', 1),
(101, 61, 35, 'Ce code n''est valable que pour la première commande. Avez-vous déjà acheté chez nous ?', 1),
(102, 35, 61, 'Ah oui, c''est ma deuxième commande. Tant pis !', 1),
(103, 61, 35, 'Je vous offre la livraison gratuite exceptionnellement. Passez la commande.', 1);
INSERT INTO `messages` (`id`, `sender_id`, `receiver_id`, `message`, `is_read`) VALUES 
(104, 34, 58, 'Bonjour, j''ai passé commande hier, quand est-ce que ça sera expédié ?', 1),
